import { dummyProducts } from "@/lib/dummyData";
import Image from "next/image";
import React from "react";
import AddToCart from "../cart/AddToCart";

const ItemCard = () => {
  return (
    <>
      <main className="max-w-full h-full flex relative overflow-y-hidden">
        <div className="w-full m-4 grid flex grid-cols-1 items-start justify-center gap-4 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 overflow-y-scroll">
          {dummyProducts.map((products) => (
            <div
              className="w-full flex flex-col justify-start items-center w-93 h-60 rounded-lg flex-grow  bg-[#FFF7D1]"
              key={products.id}
            >
              <Image
                key={products.id}
                src={products.imageUrl}
                width={150}
                height={150}
                alt="image"
                className="object-contain h-[150] w-[150]"
              />
              <h3 className="md:text-xl m-0">{products.productName}</h3>
              {/* <p className="text-sm pt-5 ml-5 mr-5">{products.description}</p> */}
              <div className="flex self-stretch items-center m-3 mt-auto justify-between">
                <div className="flex flex-col leading-4">
                  <span className="text-sm font-bold text-gray-700 dark:text-white">
                    Price: ₱{products.price}
                  </span>
                  <span className="text-sm font-bold text-gray-700 dark:text-white">
                    Quantity: {products.quantity}
                  </span>
                </div>
                <AddToCart id={products.id} prodQuantity={products.quantity} />
              </div>
            </div>
          ))}
        </div>
      </main>
    </>
  );
};
export default ItemCard;
